on\" class=\"modal-default-button text-2xl py-1\"  @click=\"closeModal()\">\n                &times;\n              </button>\n            </div>\n            <div class=\"modal-body\">\n              <div class=\"flex items-center\">\n                <div class=\"w-full lg:w-1/4\"> \n                  <label for=\"type\" class=\"tw-form-label\">Type</label>\n                </div>\n                <div class=\"my-2 w-full lg:w-3/4\">\n                  <select name=\"type\" v-model=\"type\" id=\"type\" class=\"tw-form-control w-full\">\n                    <option value=\"\" disabled>Select Type</option>\n                    <option v-for=\"types in typelist\" v-bind:value=\"types.id\">{{ types.name }}</option>\n                  </select>\n                  <span v-if=\"errors.type\" class=\"text-red-500 text-xs font-semibold\">{{errors.type[0]}}</span>\n                </div>\n              </div>\n            </div>\n            <div class=\"modal-body\">\n              <div class=\"flex items-center\">\n                <div class=\"w-full lg:w-1/4\"> \n                  <label for=\"title\" class=\"tw-form-label\">Title</label>\n                </div>\n                <div class=\"my-2 w-full lg:w-3/4\">\n                  <input type=\"text\" name=\"title\" v-model=\"title\" id=\"title\" class=\"tw-form-control w-full\" placeholder=\"Enter Title\">\n                  <span v-if=\"errors.title\" class=\"text-red-500 text-xs font-semibold\">{{errors.title[0]}}</span>\n                </div>\n              </div>\n            </div>\n            <div class=\"modal-body\">\n              <div class=\"flex items-center\">\n                <div class=\"w-full lg:w-1/4\"> \n                  <label for=\"attachment\" class=\"tw-form-label\">Attach File</label>\n                </div>\n                <div class=\"my-2 w-full lg:w-3/4\">\n                  <input type=\"file\" name=\"attachment\" @change=\"OnFileSelected\" class=\"tw-form-control w-full\">\n                  <span v-if=\"errors.attachment\" class=\"text-red-500 text-xs font-semibold\">{{errors.attachment[0]}}</span>\n                </div>\n              </div>\n            </div>\n            <div class=\"my-6\">\n              <a href=\"#\" class=\"btn btn-submit blue-bg text-white rounded px-3 py-1 mr-3 text-sm font-medium\" @click=\"update(list.id)\">Submit</a>\n            </div>\n          </div>\n        </div>\n      </div>\n    </div>\n  </div>\n</template>\n\n<script>\n  import { bus } from \"../../../app\";\n  export default {\n    props:['url' , 'name'],\n    data () {\n      return {\n        profile_tab:'',\n        lists:[],\n        type:'',\n        title:'',\n        tab:'',   \n        attachment:'', \n        typelist:[{id:'certificates' , name:'Certificates'} , {id:'id_proof' , name:'ID Proof'} , {id:'others' , name:'Others'}],\n        errors:[],\n        success:null,  \n      }\n    },\n\n    methods:\n    {\n      getData()\n      {\n        axios.get('/admin/document/get/'+this.name).then(response => {\n          this.lists = response.data.data;\n          //console.log(this.lists)\n        });\n      },\n\n      addModal()\n      {\n        this.tab = 'add';\n      },\n\n      editModal(id)\n      {\n        axios.get('/admin/document/edit/list/'+id).then(response => {\n          this.title = response.data.title;\n          this.type = response.data.type;\n        });\n        this.tab = id;\n      },\n\n      closeModal()\n      {\n        this.tab = 0;\n      },\n\n      OnFileSelected(event)\n      {\n        this.attachment = event.target.files[0];\n      },\n\n      submit()\n      {\n        this.errors=[];\n        this.success=null;\n\n        let formData=new FormData(); \n\n        formData.append('type',this.type); \n        formData.append('title',this.title); \n        formData.append('attachment',this.attachment); \n\n        axios.post('/admin/document/add/'+this.name,formData,{headers: {'Content-Type': 'multipart/form-data'}}).then(response => {     \n          this.success = response.data.success;\n          this.closeModal();\n        }).catch(error => {\n          this.errors = error.response.data.errors;\n        });\n      },\n\n      update(id)\n      {\n        this.errors=[];\n        this.success=null;\n\n        let formData=new FormData(); \n\n        formData.append('type',this.type); \n        formData.append('title',this.title); \n        formData.append('attachment',this.attachment); \n\n        axios.post('/admin/document/edit/'+this.name+'/'+id,formData,{headers: {'Content-Type': 'multipart/form-data'}}).then(response => {     \n          this.success = response.data.success;\n          this.closeModal();\n        }).catch(error => {\n          this.errors = error.response.data.errors;\n        });\n      },\n\n      deleteDoc(id) \n      {\n        var thisswal = this;\n        swal({\n          title: 'Are you sure',\n          text: 'Do you want to delete this Document ?',\n          icon: \"info\",\n          buttons: [\n            'No',\n            'Yes'\n          ],\n          dangerMode: true,\n        }).then(function(isConfirm) {\n          if (isConfirm) \n          {\n            axios.get(thisswal.url+ '/admin/document/delete/'+ id).then(response => {\n              thisswal.success = response.data.success;\n              window.location.reload();\n            }); \n          }\n          else \n          {\n            swal(\"Cancelled\");\n          }\n        });\n      },\n    },\n\n    created()\n    {   \n      this.getData();  \n      bus.$on(\"dataProfileTab\", data => {\n        if(data!='')\n        {\n          this.profile_tab=data;                   \n        }\n      });    \n    }\n  }\n</script>\n\n<style scoped>\n  .modal-mask {\n    position: fixed;\n    z-index: 9998;\n    top: 0;\n    left: 0;\n    width: 100%;\n    height: 100%;\n    background-color: rgba(0, 0, 0, .5);\n    display: table;\n    transition: opacity .3s ease;\n  